<div class="row justify-content-center"><div class="col-lg-7"><div class="archive-card p-4"><p class="text-uppercase fw-semibold archive-kicker-dark mb-1">Trust & safety</p><h1 class="h3">Open dispute for order #<?= e((string)$order['id']) ?></h1><p class="text-muted">Opening a dispute freezes automatic settlement. Messages and existing payment proofs become available to admins reviewing the case.</p><?php if($errors!==[]):?><div class="alert alert-danger"><ul class="mb-0"><?php foreach($errors as $error):?><li><?= e($error) ?></li><?php endforeach;?></ul></div><?php endif;?><form method="post" action="<?= e(url('/disputes/store?order_id='.(int)$order['id'])) ?>"><div class="mb-3"><label class="form-label">Reason</label><select class="form-select" name="reason" required><option value="">Choose reason</option><?php foreach(['non_payment'=>'Non-payment','non_delivery'=>'Non-delivery','wrong_card'=>'Wrong card','condition_mismatch'=>'Condition mismatch','counterfeit_concern'=>'Counterfeit concern','other'=>'Other'] as $value=>$label):?><option value="<?= e($value) ?>" <?= ($old['reason']??'')===$value?'selected':'' ?>><?= e($label) ?></option><?php endforeach;?></select></div><div class="mb-3"><label class="form-label">What happened?</label><textarea class="form-control" name="details" minlength="20" maxlength="3000" rows="6" required><?= e($old['details']??'') ?></textarea></div><div class="mb-3"><label class="form-label">Evidence notes</label><textarea class="form-control" name="evidence_notes" maxlength="3000" rows="4" placeholder="Reference payment proof, tracking, or order messages."><?= e($old['evidence']??'') ?></textarea></div><button class="btn btn-danger">Open dispute and freeze settlement</button></form></div></div></div>
